package main

import (
	"context"
	"sort"
	"strconv"
	"strings"
	"sync"
	"time"
)

func solve(input string) string {
	lines := strings.Split(strings.TrimSpace(input), "\n")
	type result struct {
		name   string
		status string
	}
	results := make([]result, len(lines))
	var wg sync.WaitGroup
	for i, line := range lines {
		parts := strings.Fields(line)
		name := parts[0]
		duration, _ := strconv.Atoi(parts[1])
		deadline, _ := strconv.Atoi(parts[2])
		wg.Add(1)
		go func(idx int, n string, dur, dl int) {
			defer wg.Done()
			ctx, cancel := context.WithTimeout(context.Background(), time.Duration(dl)*time.Millisecond)
			defer cancel()
			workDone := make(chan struct{})
			go func() {
				time.Sleep(time.Duration(dur) * time.Millisecond)
				close(workDone)
			}()
			// TODO: select on ctx.Done() vs workDone and set results[idx]
			_ = ctx
			_ = workDone
		}(i, name, duration, deadline)
	}
	wg.Wait()
	sort.Slice(results, func(i, j int) bool {
		return results[i].name < results[j].name
	})
	var out []string
	for _, r := range results {
		out = append(out, r.name+" "+r.status)
	}
	return strings.Join(out, "\n")
}
